/**
 * Reads each configured library's real `.agda-lib` file (from the OS path
 * in deploy.local.json) and writes `deploy-assets/generated-libraries.mjs`,
 * mapping each library name to the `includeSubpath`, `libraryName`, and
 * `agdaLibFilename` parsed directly from that file.
 *
 * The generated file is a plain ES module imported by
 * src/lib/runtime/interface.ts at build time (Vite inlines it into the
 * compiled bundle). It's gitignored — like everything else this script reads
 * from (deploy.local.json may not exist on a fresh clone).
 *
 * A library whose .agda-lib isn't readable is skipped with a warning rather
 * than failing the whole run, so `predev`/`precheck`/`prebuild` can always
 * produce the file (even if empty) for interface.ts's import to resolve —
 * letting `npm run check`/`npm run build` succeed in CI without
 * deploy.local.json being present.
 *
 * Usage: node deploy-assets/generate-library-info.mjs
 */

import { readFile, writeFile } from 'node:fs/promises'
import { basename, join, relative } from 'node:path'
import { REPO_ROOT, getLocalLibraries } from './resolve-deploy-config.mjs'
import { parseAgdaLibInclude, parseAgdaLibName } from './agda-lib-utils.mjs'

const OUT_PATH = join(REPO_ROOT, 'deploy-assets', 'generated-libraries.mjs')

async function main() {
  let libs
  try {
    libs = getLocalLibraries()
  } catch {
    libs = []
  }

  const info = {}
  let skipped = 0
  for (const lib of libs) {
    let src
    try {
      src = await readFile(lib.agdaLibPath, 'utf8')
    } catch {
      console.warn(`  skipping ${lib.name}: could not read ${lib.agdaLibPath} (check agdaLibPath in deploy.local.json, then re-run \`npm run setup\`)`)
      skipped++
      continue
    }
    info[lib.agdaLibPath] = {
      name: lib.name,
      includeSubpath: parseAgdaLibInclude(src),
      libraryName: parseAgdaLibName(src),
      agdaLibFilename: basename(lib.agdaLibPath),
    }
  }

  const lines = [
    '// Generated by deploy-assets/generate-library-info.mjs — do not edit by hand.',
    '// Re-run `npm run setup` after changing deploy.local.json or any .agda-lib file.',
    '',
    '/** @type {Record<string, { name: string, includeSubpath: string, libraryName: string, agdaLibFilename: string }>} */',
    `export const GENERATED_LIBRARY_INFO = ${JSON.stringify(info, null, 2)}`,
    '',
  ]
  await writeFile(OUT_PATH, lines.join('\n'))
  console.log(`Wrote ${Object.keys(info).length} librar${Object.keys(info).length === 1 ? 'y' : 'ies'}${skipped > 0 ? ` (${skipped} skipped)` : ''} to ${relative(REPO_ROOT, OUT_PATH)}`)
}

main().catch(err => { console.error(err); process.exit(1) })
